def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="Agent Fox V1A-2R1 refined static launcher and reference bridge")
    parser.add_argument("--self-test", action="store_true")
    subparsers = parser.add_subparsers(dest="command")
    build = subparsers.add_parser("build")
    build.add_argument("--project-root", type=Path, default=DEFAULT_PROJECT_ROOT)
    build.add_argument("--v1a2-dir", type=Path, default=DEFAULT_V1A2_DIR)
    build.add_argument("--output-dir", type=Path, default=DEFAULT_OUTPUT_DIR)
    build.add_argument("--mission-id", default=DEFAULT_MISSION_ID)
    build.add_argument("--verify-existing", action="store_true")
    query = subparsers.add_parser("query")
    query.add_argument("--index-dir", type=Path, default=DEFAULT_OUTPUT_DIR)
    query.add_argument("--mode", required=True, choices=["search", "explain", "trace-launcher", "find-symbol", "find-setting", "find-references", "compare-known-good"])
    query.add_argument("--term")
    query.add_argument("--path")
    query.add_argument("--limit", type=int, default=25)
    query.add_argument("--format", choices=["json", "text"], default="text")
    validate = subparsers.add_parser("validate-output")
    validate.add_argument("--index-dir", type=Path, default=DEFAULT_OUTPUT_DIR)
    return parser


def print_human(value: Any, indent: int = 0) -> None:
    prefix = "  " * indent
    if isinstance(value, dict):
        for key, item in value.items():
            if isinstance(item, (dict, list)):
                print(f"{prefix}{key}:")
                print_human(item, indent + 1)
            else:
                print(f"{prefix}{key}: {item}")
    elif isinstance(value, list):
        for item in value:
            if isinstance(item, (dict, list)):
                print(f"{prefix}-")
                print_human(item, indent + 1)
            else:
                print(f"{prefix}- {item}")
    else:
        print(f"{prefix}{value}")


def validate_output(index_dir: Path) -> dict[str, Any]:
    indexes = load_indexes(index_dir)
    receipt = indexes["REFINED_BRIDGE_RECEIPT.json"]
    if receipt.get("result") != "launcher_trace_precision_and_reference_sharding_complete":
        raise ValueError("refined_result_not_complete")
    for item in receipt.get("core_outputs_before_receipt", []):
        path = index_dir / Path(item["name"])
        if not path.is_file() or path.stat().st_size != item["size_bytes"] or sha256_file(path) != item["sha256"]:
            raise ValueError(f"refined_output_hash_mismatch:{path}")
    launcher = indexes["REFINED_STATIC_LAUNCHER_INDEX.json"]
    metrics = launcher.get("false_edge_metrics", {})
    for key in ("shell_builtin_launch_edge_count", "url_as_filesystem_edge_count", "comment_launch_edge_count", "unresolved_confirmed_target_count"):
        if metrics.get(key) != 0:
            raise ValueError(f"launcher_precision_metric_failed:{key}:{metrics.get(key)}")
    catalog = indexes["STATIC_REFERENCE_CATALOG.json"]
    if catalog.get("global_line_record_ceiling_used") is not False:
        raise ValueError("global_reference_ceiling_still_used")
    if catalog.get("source_file_coverage_count") != indexes["STATIC_CODE_INDEX.json"].get("file_count"):
        raise ValueError("reference_file_coverage_mismatch")
    if catalog.get("shard_count") != len(catalog.get("shards", [])) or catalog.get("shard_count", 0) < 1:
        raise ValueError("reference_shard_accounting_failed")
    total = sum(path.stat().st_size for path in index_dir.rglob("*") if path.is_file())
    if total > MAX_OUTPUT_BYTES:
        raise ValueError(f"output_ceiling_exceeded:{total}")
    return {"result": "AGENT_FOX_V1A2R1_OUTPUT_VALIDATED", "output_bytes": total, "launcher_records": launcher.get("record_count"), "reference_shards": catalog.get("shard_count")}


def main(argv: list[str] | None = None) -> int:
    parser = build_parser()
    args = parser.parse_args(argv)
    if args.self_test:
        self_test()
        return 0
    if args.command == "build":
        outputs, shards = build_bridge(args.project_root, args.v1a2_dir, args.mission_id)
        serialized = finalize_outputs(outputs, shards)
        write_outputs(args.output_dir, serialized, args.verify_existing)
        if not args.verify_existing:
            print(json.dumps({"result": "launcher_trace_precision_and_reference_sharding_complete", "output_dir": norm_win(args.output_dir), "output_files": len(serialized), "output_bytes": sum(len(value) for value in serialized.values()), "network_used": False, "launchers_executed": False}, indent=2))
        return 0
    if args.command == "query":
        result = run_query(args.index_dir, args.mode, args.term, args.path, args.limit)
        if args.format == "json":
            print(json.dumps(result, ensure_ascii=False, indent=2, sort_keys=True))
        else:
            print_human(result)
        return 0
    if args.command == "validate-output":
        print(json.dumps(validate_output(args.index_dir), indent=2, sort_keys=True))
        return 0
    parser.print_help()
    return 2


if __name__ == "__main__":
    raise SystemExit(main())
